class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        unordered_set<int> powerful_nums;
        for (long long i = 0, num_x = 1; num_x <= bound; ++i, num_x *= x) {
            for (long long j = 0, num_y = 1; num_y <= bound; ++j, num_y *= y) {
                int sum = num_x + num_y;
                if (sum <= bound) {
                    powerful_nums.insert(sum);
                }
                if (y == 1) break;
            }
            if (x == 1) break;
        }
        return vector<int>(powerful_nums.begin(), powerful_nums.end());
    }
};
efficiency: HIGH
time complexity: O(log(bound) * log(bound))
space complexity: O(log(bound) * log(bound))
energy implications: LOW
explanation: The solution iterates through possible values of x^i and y^j, storing unique sums in an unordered_set to avoid duplicates, and finally returns the set as a vector. It handles edge cases where x or y equals 1. 
